  function setupDragAndDrop() {
    const dropZone = document.getElementById('crypto-drop-zone');
    const fileInput = document.getElementById('dz-file-input');
    const resultsBox = document.getElementById('validator-results');

    if (!dropZone || !fileInput || !resultsBox) return;

    const newDropZone = dropZone.cloneNode(true);
    dropZone.parentNode.replaceChild(newDropZone, dropZone);

    const newFileInput = document.getElementById('dz-file-input');

    newDropZone.addEventListener('click', () => newFileInput.click());

    newFileInput.addEventListener('change', (e) => {
      const file = e.target.files[0];
      if (file) processFileForVerification(file);
    });

    newDropZone.addEventListener('dragover', (e) => {
      e.preventDefault();
      newDropZone.classList.add('dragover');
    });

    newDropZone.addEventListener('dragleave', () => {
      newDropZone.classList.remove('dragover');
    });

    newDropZone.addEventListener('drop', (e) => {
      e.preventDefault();
      newDropZone.classList.remove('dragover');
      const file = e.dataTransfer.files[0];
      if (file) processFileForVerification(file);
    });
  }

  function processFileForVerification(file) {
    const resultsBox = document.getElementById('validator-results');
    if (!resultsBox) return;

    resultsBox.style.display = 'block';

    const statusBox = document.getElementById('result-status-box');
    const statusTitle = document.getElementById('result-status-title');
    const statusDesc = document.getElementById('result-status-desc');
    const fileName = document.getElementById('meta-file-name');
    const fileHash = document.getElementById('meta-file-hash');

    statusBox.className = 'result-status-box';
    statusTitle.innerText = 'CALCULANDO HASH...';
    statusDesc.innerText = 'Calculando firma criptográfica SHA-256 local-first...';
    fileName.innerText = file.name;
    fileHash.innerText = 'Calculando...';

    const reader = new FileReader();
    reader.onload = async function(e) {
      try {
        const arrayBuffer = e.target.result;
        const hashBuffer = await crypto.subtle.digest('SHA-256', arrayBuffer);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

        fileHash.innerText = hashHex;

        if (dbAuthHashes[hashHex]) {
          statusBox.classList.add('valid');
          statusTitle.innerText = '✔ DOCUMENTO SOBERANO AUTÉNTICO';
          statusDesc.innerText = \`Firma verificada exitosamente: "\${dbAuthHashes[hashHex]}" (Estatus publicable aprobado por ISAN-2026).\`;
        } else {
          statusBox.classList.add('invalid');
          statusTitle.innerText = '⚠ FIRMA DESCONOCIDA / ALTERACIÓN';
          statusDesc.innerText = 'El hash computado localmente no coincide con ningún documento registrado en el catálogo público oficial.';
        }
      } catch (err) {
        statusTitle.innerText = 'ERROR EN PROCESAMIENTO';
        statusDesc.innerText = 'No se pudo calcular el hash criptográfico del archivo local.';
      }
    };
    reader.readAsArrayBuffer(file);
  }

  document.addEventListener('DOMContentLoaded', setupDragAndDrop);
  document.addEventListener('astro:page-load', setupDragAndDrop);
  setupDragAndDrop();
`}</script>
